// Log de REQUERIMIENTO — clasificación exitosa, flujo de 2 pasos activado en el bot
// La tarea Planner se creará desde el bot una vez recibido el Excel del solicitante
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.requerimientosLog)) staticData.requerimientosLog = [];

const item = $input.first().json;

staticData.requerimientosLog.push({
  timestamp:   new Date().toISOString(),
  origen:      'personal',
  tipo:        'REQUERIMIENTO',
  titulo:      item.output?.titulo      || 'N/A',
  descripcion: item.output?.descripcion || 'N/A',
  solicitante: item.output?.solicitante || 'N/A',
  mensajeOriginal: item.mensaje || 'N/A',
  nota: 'Clasificación completada — Planner se creará en el bot tras recibir Excel del solicitante'
});

staticData.requerimientosLog = staticData.requerimientosLog.slice(-500);

return $input.all();

// Log de CONSULTA (no crea tarea, solo registra)
const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.consultasLog)) staticData.consultasLog = [];

const item = $input.first().json;

staticData.consultasLog.push({
  timestamp:   new Date().toISOString(),
  origen:      'personal',
  titulo:      item.output?.titulo      || 'N/A',
  descripcion: item.output?.descripcion || 'N/A',
  solicitante: item.output?.solicitante || 'N/A',
  mensajeOriginal: item.mensaje || 'N/A'
});

staticData.consultasLog = staticData.consultasLog.slice(-500);

return $input.all();

const staticData = $getWorkflowStaticData('global');
if (!Array.isArray(staticData.erroresLog)) staticData.erroresLog = [];

const item = $input.first().json;
let mensajeOriginal = 'N/A';
let solicitante = 'N/A';
try {
  mensajeOriginal = $('Validar Contrato').item?.json?.mensaje || 'N/A';
  solicitante     = $('Validar Contrato').item?.json?.solicitante?.nombre || 'N/A';
} catch(e) {}

staticData.erroresLog.push({
  timestamp:       new Date().toISOString(),
  origen:          'personal',
  error:           item.error?.message || JSON.stringify(item.error) || 'Error desconocido',
  nodo:            item.error?.node?.name || 'N/A',
  mensajeOriginal,
  solicitante
});

staticData.erroresLog = staticData.erroresLog.slice(-500);

return $input.all();

