const tipo = $json.output?.tipo || 'CONSULTA';
const metadata = {
  INCIDENCIA:    { prioridad: 5, bucket: 'Incidencias',    etiqueta: '🔴 INCIDENCIA' },
  REQUERIMIENTO: { prioridad: 3, bucket: 'Requerimientos', etiqueta: '🟡 REQUERIMIENTO' },
  CONSULTA:      { prioridad: 1, bucket: 'Consultas',      etiqueta: '🔵 CONSULTA' },
};
const meta = metadata[tipo] || { prioridad: 1, bucket: 'General', etiqueta: '⚪ ' + tipo };
return [{ json: { ...$json, meta } }];

const item = $input.first();
const output = item.json.output || {};
const input_data = item.json;
const TIPOS = ['INCIDENCIA','REQUERIMIENTO','CONSULTA','IGNORAR'];
let tipo = String(output.tipo || '').trim().toUpperCase();
if (!TIPOS.includes(tipo)) tipo = 'IGNORAR';
const titulo = String(output.titulo || 'Sin título').trim().substring(0, 60);
const descripcion = String(output.descripcion || 'Sin descripción').trim();
const solicitante_nombre = String(output.solicitante || input_data.solicitante?.nombre || 'Desconocido').trim();
const crear_tarea = ['INCIDENCIA', 'REQUERIMIENTO'].includes(tipo);

return [{
  json: {
    ...item.json,
    output: {
      tipo,
      titulo,
      descripcion,
      solicitante: solicitante_nombre,
      crear_tarea
    }
  }
}];

const item = $input.first().json;
const body = item.body || item;

// Validar campos obligatorios del contrato
const origen = String(body.origen || '').trim();
const mensaje = String(body.mensaje || '').trim();
const solicitante = body.solicitante || {};
const nombre = String(solicitante.nombre || '').trim();
const aadObjectId = String(solicitante.aadObjectId || '').trim();
const email = String(solicitante.email || '').trim();
const conversationId = String(body.conversationId || '').trim();
const timestamp = String(body.timestamp || new Date().toISOString()).trim();

if (!mensaje) {
  throw new Error('Campo "mensaje" es obligatorio.');
}
if (!nombre) {
  throw new Error('Campo "solicitante.nombre" es obligatorio.');
}

return [{
  json: {
    origen: origen || 'personal',
    mensaje,
    solicitante: {
      nombre,
      aadObjectId,
      email
    },
    conversationId,
    timestamp
  }
}];
